class Solution:
    def sumDigitDifferences(self, nums):
        s = [str(x) for x in nums]
        D = len(s[0])
        total = 0
        for col in range(D):
            for i in range(len(s)):
                for j in range(i + 1, len(s)):
                    if s[i][col] != s[j][col]:
                        total += 1
        return total

