class Solution:
    def sumDigitDifferences(self, nums):
        n = len(nums)
        s = [str(x) for x in nums]
        D = len(s[0])
        total = 0
        for col in range(D):
            freq = {}
            for row in s:
                d = row[col]
                freq[d] = freq.get(d, 0) + 1
            for cnt in freq.values():
                total += cnt * (n - cnt)
        return total // 2

