var sumDigitDifferences = function(nums) {
    const n = nums.length;
    const strs = nums.map(x => String(x));
    const D = strs[0].length;
    let total = 0;
    for (let col = 0; col < D; col++) {
        const freq = {};
        for (const s of strs) {
            const d = s[col];
            freq[d] = (freq[d] || 0) + 1;
        }
        for (const cnt of Object.values(freq)) {
            total += cnt * (n - cnt);
        }
    }
    return total / 2;
};
